rubric.en:
Expected code/algorithm:
isPentagonalNat(x) {
  if (x <= 0) failure;
  a = 1 + 24 * x;
  b = int(sqrt(a));
  if (b*b == a && (1+b)%6 == 0)
    return true;
  else
    return false;
}

